sql:
SELECT total_wins
FROM coaches
ORDER BY total_wins DESC;

SELECT coach_name, nationality, total_wins, total_losses
FROM coaches
ORDER BY total_wins DESC;

external_knowledge:
External Knowledge: 
- 'best performing coaches' refers to the coaches with the highest win percentage for each team; 
- 'cumulative win percentages' means the total win percentage for each coach over their tenure, ordered by date.
